236: fn trailing_newline(s: &str) -> &str {
237:     if s.ends_with("\r\n") {
238:         "\r\n"
239:     } else if s.ends_with("\r") {
240:         "\r"
241:     } else if s.ends_with("\n") {
242:         "\n"
243:     } else {
244:         ""
245:     }
246: }
